wrong_code:
// WRONG — reads 4 bytes from offset 0x00
// but mstore writes 32 bytes, selector is in the LAST 4 bytes
mstore(0x00, 0xf4d678b8) // InsufficientBalance()
revert(0x00, 0x04)        // returns first 4 bytes = 0xf4d678b8 + 28 zero bytes stripped to 4

correct_code:
// CORRECT — selector sits at bytes [28..32] of the 32-byte word
// revert(0x1c, 0x04) reads exactly those 4 bytes
mstore(0x00, 0xf4d678b8) // InsufficientBalance() written to slot 0x00
revert(0x1c, 0x04)        // 0x1c = 28, reads bytes [28..32] = the selector
